function handleOpen(e: Event) {
	const el = e.currentTarget;
	const triggerEl = e.currentTarget;
	if (!isHTMLElement(el) || !isHTMLElement(triggerEl)) return;
	open.set(true);
	activeTrigger.set(triggerEl);
}

function handleClose() {
