export function nextEnabledIndex({ items, index, step, isDisabled }) {
  const length = items.length;
  if (length === 0) return index;
  const disabled = isDisabled ?? ((item) => Boolean(item?.disabled));
  let candidate = moveIndex(index, step, length);
  let attempts = 0;
  while (disabled(items[candidate]) && attempts < length) {
    candidate = moveIndex(candidate, step, length);
    attempts++;
  }
  return disabled(items[candidate]) ? index : candidate;
}

export function loadConfig(cwd: string): RawConfig | undefined {
	const configPath = path.resolve(cwd, "components.json");
	if (!fs.existsSync(configPath)) return;

	try {
		const configResult = fs.readFileSync(configPath, { encoding: "utf8" });
		const config = JSON.parse(configResult);
		return parseRawConfig(config);
	} catch (e) {
		if (!(e instanceof z.ZodError)) throw e;
		const formatted = z.prettifyError(e);
		throw new ConfigError(
			`Invalid configuration found in ${highlight(configPath)}.\n\n${formatted}`
		);
	}
}

export function get_set_cookies(headers) {
	if (typeof headers.getSetCookie === 'function') {
		return headers.getSetCookie();
	}

	const set_cookie = headers.get('set-cookie');
	return set_cookie ? set_cookie_parser.splitCookiesString(set_cookie) : [];
}

export function resolve(base, path) {
	// special case
	if (path[0] === '/' && path[1] === '/') return path;

	let url = new URL(base, internal);
	url = new URL(path, url);

	return url.protocol === internal.protocol ? url.pathname + url.search + url.hash : url.href;
}

export function isHooksFile(fileName: string, basename: string, hooksPath: string): boolean {
    return (
        ((basename === 'index.ts' || basename === 'index.js') &&
            fileName.slice(0, -basename.length - 1).endsWith(hooksPath)) ||
        fileName.slice(0, -path.extname(basename).length).endsWith(hooksPath)
    );
}

export function getDiagnosticTag(diagnostic: ts.Diagnostic): DiagnosticTag[] {
    const tags: DiagnosticTag[] = [];
    if (diagnostic.reportsUnnecessary) {
        tags.push(DiagnosticTag.Unnecessary);
    }
    if (diagnostic.reportsDeprecated) {
        tags.push(DiagnosticTag.Deprecated);
    }
    return tags;
}

export function updateRelativeImport(oldPath: string, newPath: string, relativeImportPath: string) {
    let newImportPath = path
        .join(path.relative(newPath, oldPath), relativeImportPath)
        .replace(/\\/g, '/');
    if (!newImportPath.startsWith('.')) {
        newImportPath = './' + newImportPath;
    }
    return newImportPath;
}

export const canChangeSlide = ({
  lastSlideChange,
  slideDuration,
  slideDurationRatio = 1
}: {
  lastSlideChange: number;
  slideDuration: number;
  slideDurationRatio?: number; // Allows for starting a new transition before the previous completes
}) => {
  if (lastSlideChange && Date.now() - lastSlideChange < slideDuration * slideDurationRatio) {
    console.warn("Can't change slide yet, too soon");
    return false;
  }

  return true;
};

function generate_redirects(redirects) {
	const rules = Array.from(
		redirects.entries(),
		([path, redirect]) => `${path} ${redirect.location} ${redirect.status}`
	).join('\n');

	return `
# === START AUTOGENERATED SVELTE PRERENDERED REDIRECTS ===
${rules}
# === END AUTOGENERATED SVELTE PRERENDERED REDIRECTS ===
`.trimEnd();
}

(input, keypath) => {
	assert_string(input, keypath);

	if (input) {
