export function focusWithoutScroll(element: HTMLElement) {
	const doc = getDocument(element);
	const win = getWindow(element);
	const scrollPosition = {
		x: win.pageXOffset || doc.documentElement.scrollLeft,
		y: win.pageYOffset || doc.documentElement.scrollTop,
	};
	element.focus();
	win.scrollTo(scrollPosition.x, scrollPosition.y);
}

export function focusFirst(
	candidates: HTMLElement[],
	{ select = false } = {},
	getActiveElement: () => HTMLElement | null
) {
	const previouslyFocusedElement = getActiveElement();
	for (const candidate of candidates) {
		focus(candidate, { select });
		if (getActiveElement() !== previouslyFocusedElement) return true;
	}
}

export function restoreScroll(state: ScrollHistoryState | null): void {
    // If this exists, then this is a back navigation: restore the scroll position
    if (state) {
        window.scrollTo(state.__svelte_spa_router_scrollX || 0, state.__svelte_spa_router_scrollY || 0)
    }
    else {
        // Otherwise this is a forward navigation: scroll to top
        window.scrollTo(0, 0)
    }
}

