export function removeUndefined<T extends object>(
	obj: T
): {
	[K in keyof T]-?: Exclude<T[K], undefined>;
} {
	const result = {} as { [K in keyof T]-?: Exclude<T[K], undefined> };
	for (const key in obj) {
		const value = obj[key];
		if (value !== undefined) {
			// eslint-disable-next-line @typescript-eslint/no-explicit-any
			result[key] = value as any;
		}
	}
	return result;
}

function escape(str) {
	return (
		str
			.normalize()
			// escape [ and ] before escaping other characters, since they are used in the replacements
			.replace(/[[\]]/g, '\\$&')
			// replace %, /, ? and # with their encoded versions because decode_pathname leaves them untouched
			.replace(/%/g, '%25')
			.replace(/\//g, '%2[Ff]')
			.replace(/\?/g, '%3[Ff]')
			.replace(/#/g, '%23')
			// escape characters that have special meaning in regex
			.replace(/[.*+?^${}()|\\]/g, '\\$&')
	);
}

export function getTsCheckComment(str = ''): string | undefined {
    const comments = str.match(commentsRegex)?.[0];
    if (comments) {
        const tsCheck = comments.match(tsCheckRegex);
        if (tsCheck) {
            // second-last entry is the capturing group with the exact ts-check wording
            return `// ${tsCheck[tsCheck.length - 3]}${ts.sys.newLine}`;
        }
    }
}

function matchToParams(
    match: Record<string, string | null> | RegExpExecArray
): Record<string, string> | RegExpExecArray | null {
    // Preserve all keys, including null values for unmatched optional params
    return match && typeof match == 'object' && Object.keys(match).length ? match as RegExpExecArray | Record<string, string> : null
}
